using System;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class Event
{
    public int Id { get; set; }
    public string Name { get; set; }
    public int AvailableSeats { get; set; }
    public byte[] RowVersion { get; set; }
}

public class Ticket
{
    public int Id { get; set; }
    public int EventId { get; set; }
    public string CustomerEmail { get; set; }
    public int Quantity { get; set; }
    public DateTime PurchaseDate { get; set; }
    public Event Event { get; set; }
}

public class BookingContext : DbContext
{
    public DbSet<Event> Events { get; set; }
    public DbSet<Ticket> Tickets { get; set; }

    public BookingContext(DbContextOptions<BookingContext> options) : base(options)
    {
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Event>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.Name).IsRequired().HasMaxLength(200);
            entity.Property(e => e.AvailableSeats).IsRequired();
            entity.Property(e => e.RowVersion)
                .IsRowVersion()
                .IsConcurrencyToken();
        });

        modelBuilder.Entity<Ticket>(entity =>
        {
            entity.HasKey(t => t.Id);
            entity.Property(t => t.CustomerEmail).IsRequired().HasMaxLength(100);
            entity.Property(t => t.Quantity).IsRequired();
            entity.Property(t => t.PurchaseDate).IsRequired();
            entity.HasOne(t => t.Event)
                .WithMany()
                .HasForeignKey(t => t.EventId)
                .OnDelete(DeleteBehavior.Restrict);
        });
    }
}

public class TicketPurchaseResult
{
    public bool Success { get; set; }
    public string Message { get; set; }
    public Ticket Ticket { get; set; }
}

public class EventBookingService
{
    private readonly BookingContext _context;
    private readonly int _maxRetries;

    public EventBookingService(BookingContext context, int maxRetries = 3)
    {
        _context = context;
        _maxRetries = maxRetries;
    }

    public async Task<TicketPurchaseResult> PurchaseTicketsAsync(int eventId, string customerEmail, int quantity)
    {
        if (quantity <= 0)
        {
            return new TicketPurchaseResult
            {
                Success = false,
                Message = "Quantity must be greater than zero."
            };
        }

        if (string.IsNullOrWhiteSpace(customerEmail))
        {
            return new TicketPurchaseResult
            {
                Success = false,
                Message = "Customer email is required."
            };
        }

        int retryCount = 0;

        while (retryCount < _maxRetries)
        {
            try
            {
                using var transaction = await _context.Database.BeginTransactionAsync(
                    System.Data.IsolationLevel.Serializable);

                try
                {
                    var eventEntity = await _context.Events
                        .FirstOrDefaultAsync(e => e.Id == eventId);

                    if (eventEntity == null)
                    {
                        return new TicketPurchaseResult
                        {
                            Success = false,
                            Message = "Event not found."
                        };
                    }

                    if (eventEntity.AvailableSeats < quantity)
                    {
                        return new TicketPurchaseResult
                        {
                            Success = false,
                            Message = $"Not enough seats available. Available: {eventEntity.AvailableSeats}, Requested: {quantity}"
                        };
                    }

                    eventEntity.AvailableSeats -= quantity;

                    var ticket = new Ticket
                    {
                        EventId = eventId,
                        CustomerEmail = customerEmail,
                        Quantity = quantity,
                        PurchaseDate = DateTime.UtcNow
                    };

                    _context.Tickets.Add(ticket);

                    await _context.SaveChangesAsync();
                    await transaction.CommitAsync();

                    return new TicketPurchaseResult
                    {
                        Success = true,
                        Message = "Tickets purchased successfully.",
                        Ticket = ticket
                    };
                }
                catch
                {
                    await transaction.RollbackAsync();
                    throw;
                }
            }
            catch (DbUpdateConcurrencyException)
            {
                retryCount++;
                
                foreach (var entry in _context.ChangeTracker.Entries())
                {
                    entry.State = EntityState.Detached;
                }

                if (retryCount >= _maxRetries)
                {
                    return new TicketPurchaseResult
                    {
                        Success = false,
                        Message = "Unable to complete purchase due to high concurrency. Please try again."
                    };
                }

                await Task.Delay(50 * retryCount);
            }
            catch (Exception ex)
            {
                return new TicketPurchaseResult
                {
                    Success = false,
                    Message = $"An error occurred: {ex.Message}"
                };
            }
        }

        return new TicketPurchaseResult
        {
            Success = false,
            Message = "Purchase failed after maximum retries."
        };
    }

    public async Task<int> GetAvailableSeatsAsync(int eventId)
    {
        var eventEntity = await _context.Events
            .AsNoTracking()
            .FirstOrDefaultAsync(e => e.Id == eventId);

        return eventEntity?.AvailableSeats ?? 0;
    }

    public async Task<Event> GetEventAsync(int eventId)
    {
        return await _context.Events
            .AsNoTracking()
            .FirstOrDefaultAsync(e => e.Id == eventId);
    }
}